import express, { type Request, type Response } from 'express'
import { createClient, type SupabaseClient } from '@supabase/supabase-js'
import { promises as fs } from 'node:fs'
import os from 'node:os'
import path from 'node:path'
import { spawn } from 'node:child_process'

type JsonRecord = Record<string, unknown>

type ShowroomShortsJobRow = {
  id: string
  status: string
  source_video_url: string | null
  final_video_url: string | null
  duration_seconds: number | null
  updated_at?: string | null
}

type ShowroomBasicShortsDraftRow = {
  id: string
  status: string
  display_name?: string | null
  industry?: string | null
  product_summary?: string | null
  color_summary?: string | null
  duration_seconds: number | null
  image_order: string[] | null
  script: {
    heroLine?: string
    detailLine?: string
    detailLine2?: string
    closingLine?: string
    endingTitle?: string
    endingSubtitle?: string
  } | null
  final_video_url: string | null
  render_error?: string | null
  updated_at?: string | null
}

type ImageAssetRow = {
  id: string
  cloudinary_url: string | null
  thumbnail_url: string | null
  product_name?: string | null
  color_name?: string | null
}

type ActiveJobState = {
  status: 'queued' | 'processing' | 'completed' | 'failed'
  updatedAt: string
  error?: string | null
}

const app = express()
app.use(express.json({ limit: '1mb' }))

const PORT = Number(process.env.PORT || 8080)
const VIDEO_BUCKET = 'showroom-shorts-videos'
const OUTPUT_WIDTH = 720
const OUTPUT_HEIGHT = 1280
const VIDEO_WIDTH = 720
const VIDEO_HEIGHT = 700
const VIDEO_Y = 290
const DEFAULT_DURATION_SECONDS = 10
const AFTER_HOLD_SECONDS = 2
const WORKER_TOKEN = process.env.SHOWROOM_SHORTS_WORKER_TOKEN?.trim() || ''
const DEFAULT_BGM_URL =
  'https://findgagu-os-cursor.vercel.app/assets/bgm/bright-lines-new-light-sample-b-24-34.mp3'
const BGM_URL = process.env.SHOWROOM_SHORTS_BGM_URL?.trim() || DEFAULT_BGM_URL
const BODY_FONT_FILE =
  process.env.SHOWROOM_SHORTS_FONT_FILE?.trim() ||
  '/usr/share/fonts/opentype/noto/NotoSansCJK-Regular.ttc'
const BOLD_FONT_FILE =
  process.env.SHOWROOM_SHORTS_BOLD_FONT_FILE?.trim() ||
  '/usr/share/fonts/opentype/noto/NotoSansCJK-Bold.ttc'
const DISPLAY_FONT_FILE =
  process.env.SHOWROOM_SHORTS_DISPLAY_FONT_FILE?.trim() ||
  '/app/assets/fonts/ghanachoco.woff'
const TITLE_OVERLAY_PNG_BASE64 =
  ''
const SUPABASE_URL = getEnv('SUPABASE_URL')
const SUPABASE_SERVICE_ROLE_KEY = getEnv('SUPABASE_SERVICE_ROLE_KEY')

const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY, {
  auth: { persistSession: false, autoRefreshToken: false },
})

const activeJobs = new Map<string, ActiveJobState>()
const queuedJobs: string[] = []
let queueRunning = false
const activeBasicDrafts = new Map<string, ActiveJobState>()
const queuedBasicDrafts: string[] = []
let basicQueueRunning = false

app.get('/health', (_req, res) => {
  res.json({
    ok: true,
    service: 'showroom-shorts-worker',
    queueDepth: queuedJobs.length,
    basicQueueDepth: queuedBasicDrafts.length,
    activeJobs: Array.from(activeJobs.entries()).map(([jobId, state]) => ({
      jobId,
      ...state,
    })),
    activeBasicDrafts: Array.from(activeBasicDrafts.entries()).map(([draftId, state]) => ({
      draftId,
      ...state,
    })),
  })
})

app.post('/jobs/compose', requireWorkerAuth, async (req, res) => {
  const jobId = getString(req.body?.jobId)
  if (!jobId) {
    res.status(400).json({ ok: false, message: 'jobId가 필요합니다.' })
    return
  }

  try {
    const job = await getJob(jobId)
    if (!job) {
      res.status(404).json({ ok: false, message: '숏츠 작업을 찾지 못했습니다.' })
      return
    }

    if (!job.source_video_url) {
      res.status(400).json({ ok: false, message: '원본 영상이 없어 서버 합성을 시작할 수 없습니다.' })
      return
    }

    const existingState = activeJobs.get(jobId)
    if (existingState?.status === 'queued' || existingState?.status === 'processing') {
      res.status(202).json({
        ok: true,
        jobId,
        status: existingState.status,
        message: existingState.status === 'processing' ? '이미 서버 합성이 진행 중입니다.' : '이미 합성 대기열에 있습니다.',
      })
      return
    }

    if (existingState?.status === 'failed' || existingState?.status === 'completed') {
      activeJobs.delete(jobId)
    }

    await updateJob(jobId, {
      status: 'composition_queued',
      final_video_url: null,
      updated_at: new Date().toISOString(),
    })
    await insertLog(jobId, 'composition_queued', 'Railway 워커 합성 대기열에 등록했습니다.')

    activeJobs.set(jobId, {
      status: 'queued',
      updatedAt: new Date().toISOString(),
      error: null,
    })
    queuedJobs.push(jobId)
    void drainQueue()

    res.status(202).json({
      ok: true,
      jobId,
      status: 'queued',
      message: 'Railway 워커 합성 요청을 등록했습니다.',
    })
  } catch (error) {
    const message = error instanceof Error ? error.message : '합성 요청 처리 중 오류가 발생했습니다.'
    res.status(500).json({ ok: false, message })
  }
})

app.get('/jobs/:id', requireWorkerAuth, async (req, res) => {
  const jobId = getString(req.params.id)
  if (!jobId) {
    res.status(400).json({ ok: false, message: 'jobId가 필요합니다.' })
    return
  }

  try {
    const job = await getJob(jobId)
    if (!job) {
      res.status(404).json({ ok: false, message: '숏츠 작업을 찾지 못했습니다.' })
      return
    }

    const state = activeJobs.get(jobId)
    const responseStatus = state?.status ?? mapWorkerStatus(job.status, job.final_video_url)
    res.json({
      ok: true,
      jobId,
      status: responseStatus,
      jobStatus: job.status,
      sourceVideoUrl: job.source_video_url,
      finalVideoUrl: job.final_video_url,
      error: state?.error ?? null,
    })
  } catch (error) {
    const message = error instanceof Error ? error.message : '합성 상태 조회 중 오류가 발생했습니다.'
    res.status(500).json({ ok: false, message })
  }
})

app.post('/jobs/basic', requireWorkerAuth, async (req, res) => {
  const draftId = getString(req.body?.draftId)
  if (!draftId) {
    res.status(400).json({ ok: false, message: 'draftId가 필요합니다.' })
    return
  }

  try {
    const draft = await getBasicShortsDraft(draftId)
    if (!draft) {
      res.status(404).json({ ok: false, message: '기본 쇼츠 요청을 찾지 못했습니다.' })
      return
    }

    const existingState = activeBasicDrafts.get(draftId)
    if (existingState?.status === 'queued' || existingState?.status === 'processing') {
      res.status(202).json({
        ok: true,
        draftId,
        status: existingState.status,
        finalVideoUrl: draft.final_video_url,
        error: existingState.error ?? null,
        message: existingState.status === 'processing' ? '이미 기본 쇼츠 렌더링이 진행 중입니다.' : '이미 기본 쇼츠 렌더링 대기열에 있습니다.',
      })
      return
    }

    if (existingState?.status === 'failed' || existingState?.status === 'completed') {
      activeBasicDrafts.delete(draftId)
    }

    await updateBasicShortsDraft(draftId, {
      status: 'render_queued',
      final_video_url: null,
      render_error: null,
      updated_at: new Date().toISOString(),
    })

    activeBasicDrafts.set(draftId, {
      status: 'queued',
      updatedAt: new Date().toISOString(),
      error: null,
    })
    queuedBasicDrafts.push(draftId)
    void drainBasicQueue()

    res.status(202).json({
      ok: true,
      draftId,
      status: 'queued',
      message: '기본 쇼츠 자동 렌더링 요청을 등록했습니다.',
    })
  } catch (error) {
    const message = error instanceof Error ? error.message : '기본 쇼츠 렌더 요청 처리 중 오류가 발생했습니다.'
    res.status(500).json({ ok: false, message })
  }
})

