app.listen(PORT, () => {
  console.log(`[showroom-shorts-worker] listening on ${PORT}`)
  void reconcileStaleComposeJobs()
  void reconcileStaleBasicShortsDrafts()
})

function getEnv(name: string) {
  const value = process.env[name]?.trim()
  if (!value) {
    throw new Error(`${name} 환경 변수가 설정되지 않았습니다.`)
  }
  return value
}

function getString(value: unknown) {
  return typeof value === 'string' && value.trim() ? value.trim() : ''
}

function requireWorkerAuth(req: Request, res: Response, next: () => void) {
  if (!WORKER_TOKEN) {
    next()
    return
  }

  const authHeader = req.header('authorization') || ''
  const expected = `Bearer ${WORKER_TOKEN}`
  if (authHeader !== expected) {
    res.status(401).json({ ok: false, message: '워커 인증에 실패했습니다.' })
    return
  }
  next()
}

async function drainQueue() {
  if (queueRunning) return
  queueRunning = true

  try {
    while (queuedJobs.length > 0) {
      const nextJobId = queuedJobs.shift()
      if (!nextJobId) continue
      await processComposeJob(nextJobId)
    }
  } finally {
    queueRunning = false
  }
}

async function drainBasicQueue() {
  if (basicQueueRunning) return
  basicQueueRunning = true

  try {
    while (queuedBasicDrafts.length > 0) {
      const nextDraftId = queuedBasicDrafts.shift()
      if (!nextDraftId) continue
      await processBasicShortsDraft(nextDraftId)
    }
  } finally {
    basicQueueRunning = false
  }
}

async function processComposeJob(jobId: string) {
  const updateActiveState = (state: ActiveJobState) => {
    activeJobs.set(jobId, state)
  }

  updateActiveState({
    status: 'processing',
    updatedAt: new Date().toISOString(),
    error: null,
  })

  const tempDir = await fs.mkdtemp(path.join(os.tmpdir(), `showroom-shorts-${jobId}-`))

  try {
    console.log(`[showroom-shorts-worker] start job=${jobId} tempDir=${tempDir}`)
    await updateJob(jobId, {
      status: 'composition_processing',
      updated_at: new Date().toISOString(),
    })
    await insertLog(jobId, 'composition_processing', 'Railway 워커에서 서버 합성을 시작했습니다.')

    const job = await getJob(jobId)
    if (!job?.source_video_url) {
      throw new Error('원본 영상 URL이 없어 서버 합성을 진행할 수 없습니다.')
    }

    const inputVideoPath = path.join(tempDir, 'source-video.mp4')
    const titleOverlayPath = path.join(tempDir, 'title-overlay.png')
    const bgmAudioPath = path.join(tempDir, 'bgm-audio')
    const outputVideoPath = path.join(tempDir, 'final-video.mp4')

    console.log(`[showroom-shorts-worker] downloading source job=${jobId}`)
    await downloadToFile(job.source_video_url, inputVideoPath)
    console.log(`[showroom-shorts-worker] source ready job=${jobId} path=${inputVideoPath}`)
    const bgmPath = BGM_URL ? await downloadBgmToFile(BGM_URL, bgmAudioPath) : null
    console.log(`[showroom-shorts-worker] bgm ready job=${jobId} path=${bgmPath ?? 'none'}`)
    const durationSeconds = await getVideoDurationSeconds(inputVideoPath, job.duration_seconds ?? DEFAULT_DURATION_SECONDS)
    console.log(`[showroom-shorts-worker] duration job=${jobId} seconds=${durationSeconds}`)
    const textPaths = await writeTextAssets(tempDir)
    await fs.writeFile(titleOverlayPath, Buffer.from(TITLE_OVERLAY_PNG_BASE64, 'base64'))
    const titleOverlayStat = await fs.stat(titleOverlayPath)
    console.log(`[showroom-shorts-worker] title overlay ready job=${jobId} bytes=${titleOverlayStat.size}`)

    console.log(`[showroom-shorts-worker] ffmpeg start job=${jobId}`)
    await runFfmpegCompose({
      inputVideoPath,
      titleOverlayPath,
      bgmPath,
      outputVideoPath,
      durationSeconds,
      textPaths,
    })
    console.log(`[showroom-shorts-worker] ffmpeg done job=${jobId} output=${outputVideoPath}`)

    const objectPath = `final/${jobId}/shorts-final-${Date.now()}.mp4`
    const videoBuffer = await fs.readFile(outputVideoPath)
    console.log(`[showroom-shorts-worker] upload start job=${jobId} bytes=${videoBuffer.length}`)
    const { error: uploadError } = await supabase.storage.from(VIDEO_BUCKET).upload(objectPath, videoBuffer, {
      contentType: 'video/mp4',
      upsert: true,
    })
    if (uploadError) {
      throw new Error(`최종 MP4 업로드에 실패했습니다: ${uploadError.message}`)
    }

    const finalVideoUrl = supabase.storage.from(VIDEO_BUCKET).getPublicUrl(objectPath).data.publicUrl
    await updateJob(jobId, {
      status: 'ready_for_review',
      final_video_url: finalVideoUrl,
      updated_at: new Date().toISOString(),
    })
    await markTargetsReady(jobId)
    await insertLog(jobId, 'composition_completed', 'Railway 워커가 최종 MP4를 생성하고 검수 준비 상태로 전환했습니다.', {
      final_video_url: finalVideoUrl,
      storage_path: objectPath,
      bgm_enabled: Boolean(bgmPath),
    })
    console.log(`[showroom-shorts-worker] completed job=${jobId} finalVideoUrl=${finalVideoUrl}`)

    updateActiveState({
      status: 'completed',
      updatedAt: new Date().toISOString(),
      error: null,
    })
  } catch (error) {
    const message = error instanceof Error ? error.message : '서버 합성 중 오류가 발생했습니다.'
    console.error(`[showroom-shorts-worker] failed job=${jobId}`, error)
    await updateJob(jobId, {
      status: 'failed',
      updated_at: new Date().toISOString(),
    }).catch(() => undefined)
    await insertLog(jobId, 'composition_failed', message).catch(() => undefined)
    updateActiveState({
      status: 'failed',
      updatedAt: new Date().toISOString(),
      error: message,
    })
  } finally {
    await fs.rm(tempDir, { recursive: true, force: true }).catch(() => undefined)
    const finalState = activeJobs.get(jobId)
    if (finalState?.status === 'completed') {
      setTimeout(() => {
        const current = activeJobs.get(jobId)
        if (current?.status === 'completed') {
          activeJobs.delete(jobId)
        }
      }, 60_000)
    }
  }
}

async function processBasicShortsDraft(draftId: string) {
  const updateActiveState = (state: ActiveJobState) => {
    activeBasicDrafts.set(draftId, state)
  }

  updateActiveState({
    status: 'processing',
    updatedAt: new Date().toISOString(),
    error: null,
  })

  const tempDir = await fs.mkdtemp(path.join(os.tmpdir(), `showroom-basic-shorts-${draftId}-`))

  try {
    await updateBasicShortsDraft(draftId, {
      status: 'render_processing',
      render_error: null,
      updated_at: new Date().toISOString(),
    })

    const draft = await getBasicShortsDraft(draftId)
    if (!draft) {
      throw new Error('기본 쇼츠 요청을 찾지 못했습니다.')
    }

    const imageIds = (draft.image_order ?? []).filter(Boolean)
    if (imageIds.length === 0) {
      throw new Error('렌더링할 이미지 순서가 없습니다.')
    }

    const imageAssets = await getImageAssetsByIds(imageIds)
    const orderedImages = imageIds
      .map((id) => imageAssets.find((asset) => asset.id === id))
      .filter((asset): asset is ImageAssetRow => Boolean(asset))

    if (orderedImages.length === 0) {
      throw new Error('렌더링할 이미지 URL을 찾지 못했습니다.')
    }

    const imagePaths: string[] = []
    for (let index = 0; index < orderedImages.length; index += 1) {
      const asset = orderedImages[index]
      const sourceUrl = asset.cloudinary_url || asset.thumbnail_url
      if (!sourceUrl) continue
      const imagePath = path.join(tempDir, `image-${index + 1}.jpg`)
      await downloadToFile(sourceUrl, imagePath)
      imagePaths.push(imagePath)
    }

    if (imagePaths.length === 0) {
      throw new Error('다운로드 가능한 이미지가 없습니다.')
    }

    const bgmAudioPath = path.join(tempDir, 'bgm-audio')
    const outputVideoPath = path.join(tempDir, 'basic-shorts-final.mp4')
    const bgmPath = BGM_URL ? await downloadBgmToFile(BGM_URL, bgmAudioPath) : null
    const durationSeconds = Math.max(draft.duration_seconds ?? DEFAULT_DURATION_SECONDS, 8)
    const productChip =
      orderedImages.map((asset) => asset.product_name?.trim()).find((value): value is string => Boolean(value)) ?? '제품 구성'
    const colorChip =
      orderedImages.map((asset) => asset.color_name?.trim()).find((value): value is string => Boolean(value)) ?? '색상 미지정'
    const textPaths = await writeBasicShortsTextAssets(tempDir, {
      heroLine: draft.script?.heroLine ?? '이 공간이 좋아 보이시나요?',
      detailLine: draft.script?.detailLine ?? '교육 공간에 맞춘 배치와 구성으로',
      detailLine2: draft.script?.detailLine2 ?? '집중감과 완성도를 잡았습니다.',
      closingLine: draft.script?.closingLine ?? '이런 구성을 우리 공간에도 적용하고 싶다면',
      productChip,
      colorChip,
      endingTitle: draft.script?.endingTitle ?? '파인드가구',
      endingSubtitle: draft.script?.endingSubtitle ?? '성공한 공간은 디테일이 다릅니다',
    })

    await runFfmpegBasicShortsCompose({
      imagePaths,
      bgmPath,
      outputVideoPath,
      durationSeconds,
      textPaths,
    })

    const objectPath = `basic/${draftId}/basic-shorts-final-${Date.now()}.mp4`
    const videoBuffer = await fs.readFile(outputVideoPath)
    const { error: uploadError } = await supabase.storage.from(VIDEO_BUCKET).upload(objectPath, videoBuffer, {
      contentType: 'video/mp4',
      upsert: true,
    })
    if (uploadError) {
      throw new Error(`기본 쇼츠 MP4 업로드에 실패했습니다: ${uploadError.message}`)
    }

    const finalVideoUrl = supabase.storage.from(VIDEO_BUCKET).getPublicUrl(objectPath).data.publicUrl
    await updateBasicShortsDraft(draftId, {
      status: 'render_completed',
      final_video_url: finalVideoUrl,
      render_error: null,
      updated_at: new Date().toISOString(),
    })
    await ensureBasicShortsTargetsAndPrepare(draftId, draft, finalVideoUrl).catch((error) => {
      console.error('[showroom-shorts-worker] basic shorts auto prepare failed', error)
    })

    updateActiveState({
      status: 'completed',
      updatedAt: new Date().toISOString(),
      error: null,
    })
  } catch (error) {
    const message = error instanceof Error ? error.message : '기본 쇼츠 자동 렌더링 중 오류가 발생했습니다.'
    await updateBasicShortsDraft(draftId, {
      status: 'render_failed',
      render_error: message,
      updated_at: new Date().toISOString(),
    }).catch(() => undefined)

    updateActiveState({
      status: 'failed',
      updatedAt: new Date().toISOString(),
      error: message,
    })
  } finally {
    await fs.rm(tempDir, { recursive: true, force: true }).catch(() => undefined)
  }
}

async function reconcileStaleComposeJobs() {
  try {
    const { data, error } = await supabase
      .from('showroom_shorts_jobs')
      .select('id, status, final_video_url, updated_at')
      .in('status', ['composition_queued', 'composition_processing'])
      .is('final_video_url', null)
      .returns<ShowroomShortsJobRow[]>()

    if (error) {
      throw new Error(error.message)
    }

    for (const job of data ?? []) {
      await updateJob(job.id, {
        status: 'failed',
        updated_at: new Date().toISOString(),
      })
      await insertLog(
        job.id,
        'composition_failed',
        '워커 재시작으로 이전 합성 상태가 중단되어 실패 처리했습니다. 다시 합성을 실행해 주세요.',
        {
          recovered_from_status: job.status,
          previous_updated_at: job.updated_at ?? null,
        }
      ).catch(() => undefined)
      console.warn(
        `[showroom-shorts-worker] reconciled stale compose job=${job.id} previousStatus=${job.status}`
      )
    }
  } catch (error) {
    console.error('[showroom-shorts-worker] stale compose reconciliation failed', error)
  }
}

async function reconcileStaleBasicShortsDrafts() {
  try {
    const { data, error } = await supabase
      .from('showroom_basic_shorts_drafts')
      .select('id, status, final_video_url, updated_at')
      .in('status', ['render_queued', 'render_processing'])
      .is('final_video_url', null)
      .returns<ShowroomBasicShortsDraftRow[]>()

    if (error) {
      throw new Error(error.message)
    }

    for (const draft of data ?? []) {
      await updateBasicShortsDraft(draft.id, {
        status: 'render_failed',
        render_error: '워커 재시작 또는 중단으로 렌더링이 끊겨 실패 처리되었습니다. 다시 제작 요청을 눌러주세요.',
        updated_at: new Date().toISOString(),
      })
    }
  } catch (error) {
    console.error('[showroom-shorts-worker] failed to reconcile stale basic drafts', error)
  }
}

